var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"낚싯대를 우물에 연결하는 것까진 성공했어.","JPN":"釣り竿を井戸に繋げるまでは上手くいった。","ENG":"The Fishing Rod has been successfully connected to the Well.","TWN":"釣魚竿已經成功連接到井裡了。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"남은 건 잠망경이 확보한 시간 좌표를 낚싯대와 동기화 시켜서 패러독스를 끌어올리는 것 뿐이야.","JPN":"あとは、潜望鏡が確保した時間座標を釣り竿に同期化して、パラドックスを引き上げるだけだよ。","ENG":"All that's left is to secure the time coordinates with the Periscope, sync it with the Fishing Rod, and pull Paradox out from there.","TWN":"剩下的就是將潛望鏡獲取到的時間座標與釣魚竿同步，然後把悖論拉回來。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"좀 더 기다려야 하네.","JPN":"もう少し時間が必要だ。","ENG":"We will have to wait a little longer.","TWN":"還要再等一會。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아직 좌표로 삼을만한 에너지 신호가 관측되지 않았어.","JPN":"まだ座標として使えるほどのエネルギー信号が観測されていない。","ENG":"No energy signals that can be used as coordinates have been observed yet.","TWN":"還沒有觀測到可以作為座標的能量訊號。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"잠깐, 갑자기 전파가 불안정해졌네.","JPN":"ちょっと、急に電波が不安定になったよ。","ENG":"Wait. The transmission signal is suddenly unstable.","TWN":"等一下，訊號突然變得不穩定了。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"위성에 침식 폭풍 같은 건 관측되지 않는데… 응?","JPN":"衛星に侵食の嵐は観測されてないはず……うん？","ENG":"The satellite isn't picking up on any Corruption storms... Hmm?","TWN":"衛星上沒有觀測到侵蝕風暴……嗯？"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"조심해! 지금 그쪽으로 엄청 많은 숫자의…!","JPN":"気をつけて！　今そっちに向かってかなり多くの……！","ENG":"Watch out! There are a lot of– headed–!","TWN":"小心！有很多……往你那邊……！"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"통신이 강제로 끊어졌군요.","JPN":"通信が強制的に途切れてしまいましたね。","ENG":"Comms have been cut off.","TWN":"通訊被強制中斷了。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"침식 폭풍은 아니라고 했어요. 그렇다면…","JPN":"侵食の嵐ではないようです。ということは……","ENG":"She said it wasn't a Corruption storm. Then...","TWN":"如果這不是侵蝕風暴，那麼……"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…누군가 우릴 방해하고 있단 뜻이군.","JPN":"……誰かに邪魔されているってわけか。","ENG":"...It means that someone has come to stop us.","TWN":"……這就表示有人在阻撓我們。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"위쪽이에요!","JPN":"上です！","ENG":"Above us!","TWN":"在上面！"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"관리자님! 이쪽으로!","JPN":"最高管理者！　こちらへ！","ENG":"Administrator! This way!","TWN":"管理者！這邊！"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"괜찮으십니까?","JPN":"大丈夫ですか？","ENG":"Are you okay?","TWN":"你還好嗎?"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…고맙네. 하마터면 머리에 직격 할 뻔했군.","JPN":"……ありがとう。危うく頭に直撃するところだった。","ENG":"...Thank you. That almost hit me right on my head.","TWN":"……謝謝。差點就被直接擊中頭部了。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"방금 떨어진 건 뭐죠? 농구공만 한 크기였는데.","JPN":"今のはなんです？　バスケットボールぐらいのサイズでしたよ。","ENG":"What was that? It was the size of a basketball.","TWN":"剛剛掉下來的是什麼？有籃球那麼大……"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"땅으로 순식간에 스며들어서 정확히는 못 봤지만…","JPN":"一瞬で地面に消えていったせいで、はっきり見ることはできませんでしたが……","ENG":"It quickly seeped into the ground, so I couldn't get a clear view of it, but...","TWN":"在一瞬間就滲入地面了，沒能看清楚……"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"…이건 침식 종양의 일종 같습니다.","JPN":"……これは侵食腫瘍の一種かと。","ENG":"...it seems like a type of Corrupted Tumor.","TWN":"……那似乎是一種侵蝕性的腫瘤。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"땅이 검게 물들고 있어요.","JPN":"地面が黒く染まってます。","ENG":"The ground is turning black.","TWN":"地面被染成了黑色的了……"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"제가 침식학을 배운 적은 없지만, 이 위에 계속 서있는 건 엄청 위험하지 않을까요?","JPN":"私、侵食学には詳しくないけど、この場所にいるのは危険では？","ENG":"I never studied Corruption, but won't it be dangerous for us to stay above it?","TWN":"我雖然沒學過侵蝕學，但我們站在上面不會很危險嗎？"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"곤란하군. 내가 잠망경의 가동 범위를 벗어나면 우물과 연결된 낚싯대가 가동을 멈출 걸세.","JPN":"困ったな。私が潜望鏡の可動範囲から離れると、井戸と繋がっている釣り竿が止まってしまう。","ENG":"This isn't good. If I leave the Periscope's range of motion, the Fishing Rod connected to the Well will stop working as Well.","TWN":"真是麻煩啊。如果我離開了潛望鏡的有效範圍，連接在井裡的釣魚竿就會停止運作。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 되면 패러독스를 구조할 타이밍도 놓치게 되겠지.","JPN":"そうなるとパラドックスを助けるタイミングを逃すことになるだろう。","ENG":"Then, we won't be there to rescue Paradox at the right time.","TWN":"那樣的話，就會錯過營救悖論的時機了。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"잠시 실례하겠습니다.","JPN":"少し失礼いたします。","ENG":"Excuse me.","TWN":"打擾了，請稍等。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};